// @ts-nocheck
import { serve } from "https://deno.land/std@0.177.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.45.0";
import { corsHeaders } from "../_shared/cors.ts";
import { isUrlSafe } from "../_shared/ssrf_validator.ts";
import { parseProductHtml, parseProductsHtml } from "../_shared/html_parser.ts";

const supabaseUrl = Deno.env.get("SUPABASE_URL") || "";
const supabaseServiceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") || "";

const supabase = createClient(supabaseUrl, supabaseServiceKey);

async function safeFetch(url: string, timeoutMs = 10000): Promise<Response> {
  if (!url || !isUrlSafe(url)) {
    throw new Error("URL inválida ou não permitida");
  }

  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

  let response: Response;
  try {
    response = await fetch(url, {
      signal: controller.signal,
      headers: {
        "Accept": "text/html,application/xhtml+xml,image/*",
        "User-Agent": "Mozilla/5.0 (compatible; GSA-Store-Bot/1.0)",
      },
    });
  } catch (e: any) {
    clearTimeout(timeoutId);
    if (e.name === 'AbortError') {
      throw new Error("Tempo limite excedido ao consultar URL");
    }
    throw new Error("Falha ao consultar a URL");
  }
  clearTimeout(timeoutId);

  // Validate redirect destination
  if (response.url && !isUrlSafe(response.url)) {
    throw new Error("URL de redirecionamento inválida ou não permitida");
  }

  return response;
}

serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: corsHeaders });
  }

  try {
    const body = await req.json();
    const { sessaoId, sessionToken, url, action, images, products, batchId } = body;

    if (!sessaoId || !sessionToken) {
      return new Response(JSON.stringify({ error: "Sessão não informada" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    // Authenticate
    const { data: actorData, error: authError } = await supabase.rpc(
      "gsa_admin_authorize_product_url_import",
      { p_sessao_id: sessaoId, p_session_token: sessionToken }
    );

    if (authError || !actorData) {
      return new Response(JSON.stringify({ error: authError?.message || "Sessão inválida ou sem permissão" }), {
        status: 403,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    // ACTION: analyze
    if (action === "analyze") {
      let response: Response;
      try {
        response = await safeFetch(url);
      } catch (e: any) {
        return new Response(JSON.stringify({ error: e.message }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" }});
      }

      const contentType = response.headers.get("content-type") || "";
      if (!contentType.includes("text/html")) {
        return new Response(JSON.stringify({ error: "A URL não retornou conteúdo HTML válido" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" }});
      }

      const text = await response.text();
      if (text.length > 2000000) {
        return new Response(JSON.stringify({ error: "Conteúdo da página muito grande (>2MB)" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" }});
      }

      const parsed = parseProductHtml(text, response.url || url);

      await supabase.from("sistema_logs").insert({
        acao: "IMPORTAR_DADOS_PRODUTO_URL",
        detalhes: JSON.stringify({ url_consultada: new URL(url).hostname, campos_encontrados: Object.keys(parsed.origem_campos), status: "sucesso" }),
        ator_tipo: actorData.ator_tipo, ator_id: actorData.ator_id, ator_nome: actorData.ator_nome,
      });

      return new Response(JSON.stringify({ success: true, data: { ...parsed, url_original: url, url_final: response.url || url, avisos: [] } }), {
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });

    // ACTION: discover_products
    } else if (action === "discover_products") {
      let response: Response;
      try {
        response = await safeFetch(url);
      } catch (e: any) {
        return new Response(JSON.stringify({ error: e.message }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" }});
      }

      const contentType = response.headers.get("content-type") || "";
      if (!contentType.includes("text/html")) {
        return new Response(JSON.stringify({ error: "A URL não retornou conteúdo HTML válido" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" }});
      }

      const text = await response.text();
      if (text.length > 2000000) {
        return new Response(JSON.stringify({ error: "Conteúdo da página muito grande (>2MB)" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" }});
      }

      const candidates = parseProductsHtml(text, response.url || url);

      await supabase.from("sistema_logs").insert({
        acao: "DESCOBRIR_PRODUTOS_PAGINA",
        detalhes: JSON.stringify({ url_consultada: new URL(url).hostname, encontrados: candidates.length, status: "sucesso" }),
        ator_tipo: actorData.ator_tipo, ator_id: actorData.ator_id, ator_nome: actorData.ator_nome,
      });

      return new Response(JSON.stringify({ success: true, data: { candidates, total: candidates.length } }), {
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });

    // ACTION: analyze_products (batch of single URLs)
    } else if (action === "analyze_products") {
       // Frontend should send individual URLs to analyze, but we can reuse 'analyze' from frontend directly.
       // For this requirement, it's safer to have the frontend loop `analyze` or we can map them here.
       // The prompt says "Processar as URLs em pequenos lotes... No máximo 10 URLs por chamada".
       const urls = body.urls || [];
       if (!Array.isArray(urls) || urls.length === 0 || urls.length > 10) {
         return new Response(JSON.stringify({ error: "Array de URLs inválido (máx 10)" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" }});
       }

       const results = await Promise.all(urls.map(async (u) => {
          try {
            const res = await safeFetch(u);
            const text = await res.text();
            if (text.length > 2000000) return { url: u, error: "Página muito grande" };
            const parsed = parseProductHtml(text, res.url || u);
            return { url: u, success: true, data: { ...parsed, url_final: res.url || u } };
          } catch (err: any) {
            return { url: u, error: err.message };
          }
       }));

       await supabase.from("sistema_logs").insert({
        acao: "ANALISAR_PRODUTOS_EM_LOTE",
        detalhes: JSON.stringify({ quantidade: urls.length, status: "sucesso" }),
        ator_tipo: actorData.ator_tipo, ator_id: actorData.ator_id, ator_nome: actorData.ator_nome,
      });

       return new Response(JSON.stringify({ success: true, data: results }), { headers: { ...corsHeaders, "Content-Type": "application/json" }});

    // ACTION: copy_images
    } else if (action === "copy_images") {
      if (!Array.isArray(images) || images.length === 0) {
         return new Response(JSON.stringify({ error: "Nenhuma imagem informada" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } });
      }

      const uploadedUrls: string[] = [];
      const failedUrls: string[] = [];

      for (const imgUrl of images) {
        try {
          const imgRes = await safeFetch(imgUrl);
          if (!imgRes.ok) throw new Error("Status " + imgRes.status);

          const blob = await imgRes.blob();
          if (blob.size > 5000000) throw new Error("Muito grande"); // 5MB

          const cType = blob.type;
          if (!['image/jpeg', 'image/png', 'image/webp'].includes(cType)) throw new Error("Tipo inválido");

          const ext = cType.split('/')[1];
          const fileName = `imports/produtos/${crypto.randomUUID()}.${ext}`;

          const { data: uploadData, error: uploadError } = await supabase.storage
            .from('gsa-store-images').upload(fileName, blob, { contentType: cType, upsert: true });

          if (uploadError || !uploadData) throw uploadError;
          const { data: publicData } = supabase.storage.from('gsa-store-images').getPublicUrl(fileName);
          uploadedUrls.push(publicData.publicUrl);
        } catch (e) {
          failedUrls.push(imgUrl);
        }
      }

      await supabase.from("sistema_logs").insert({
        acao: "IMPORTAR_DADOS_PRODUTO_URL",
        detalhes: JSON.stringify({ imagens_copiadas: uploadedUrls.length, imagens_falhas: failedUrls.length, status: "copia_imagens" }),
        ator_tipo: actorData.ator_tipo, ator_id: actorData.ator_id, ator_nome: actorData.ator_nome,
      });

      return new Response(JSON.stringify({ success: true, data: { uploaded: uploadedUrls, failed: failedUrls } }), { headers: { ...corsHeaders, "Content-Type": "application/json" } });

    // ACTION: copy_product_images (batch)
    } else if (action === "copy_product_images") {
      if (!batchId || !Array.isArray(products) || products.length === 0) {
        return new Response(JSON.stringify({ error: "Parâmetros inválidos" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" }});
      }

      const results = [];

      for (const prod of products) {
        const clientId = prod.client_id;
        const imgs = prod.images || [];
        const uploadedUrls: string[] = [];
        const failedUrls: string[] = [];

        // max 5
        const toProcess = imgs.slice(0, 5);
        for (const imgUrl of toProcess) {
          try {
            const imgRes = await safeFetch(imgUrl);
            if (!imgRes.ok) throw new Error("Status " + imgRes.status);

            const blob = await imgRes.blob();
            if (blob.size > 5000000) throw new Error("Muito grande"); // 5MB

            const cType = blob.type;
            if (!['image/jpeg', 'image/png', 'image/webp'].includes(cType)) throw new Error("Tipo inválido");

            const ext = cType.split('/')[1];
            // imports/produtos/{batch_id}/{client_id}/{uuid}.{ext}
            const fileName = `imports/produtos/${batchId}/${clientId}/${crypto.randomUUID()}.${ext}`;

            const { data: uploadData, error: uploadError } = await supabase.storage
              .from('gsa-store-images').upload(fileName, blob, { contentType: cType, upsert: true });

            if (uploadError || !uploadData) throw uploadError;
            const { data: publicData } = supabase.storage.from('gsa-store-images').getPublicUrl(fileName);
            uploadedUrls.push(publicData.publicUrl);
          } catch (e) {
            failedUrls.push(imgUrl);
          }
        }
        results.push({ client_id: clientId, uploaded: uploadedUrls, failed: failedUrls });
      }

      await supabase.from("sistema_logs").insert({
        acao: "COPIAR_IMAGENS_LOTE",
        detalhes: JSON.stringify({ batch_id: batchId, produtos_processados: products.length }),
        ator_tipo: actorData.ator_tipo, ator_id: actorData.ator_id, ator_nome: actorData.ator_nome,
      });

      return new Response(JSON.stringify({ success: true, data: results }), { headers: { ...corsHeaders, "Content-Type": "application/json" } });

    } else {
      return new Response(JSON.stringify({ error: "Ação inválida" }), {
        status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" }
      });
    }

  } catch (error: any) {
    return new Response(JSON.stringify({ error: error.message || "Erro interno do servidor" }), {
      status: 500,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});

export const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
  'Access-Control-Allow-Methods': 'POST, GET, OPTIONS, PUT, DELETE',
};

export function isUrlSafe(urlStr: string): boolean {
  try {
    const url = new URL(urlStr);

    if (url.protocol !== 'http:' && url.protocol !== 'https:') {
      return false;
    }

    if (url.username || url.password) {
      return false;
    }

    const hostname = url.hostname.toLowerCase();

    // Block localhost and standard private ranges
    if (
      hostname === 'localhost' ||
      hostname.startsWith('127.') ||
      hostname.startsWith('10.') ||
      hostname.startsWith('192.168.') ||
      hostname.startsWith('169.254.') ||
      hostname.endsWith('.internal') ||
      hostname.endsWith('.local') ||
      hostname === '::1'
    ) {
      return false;
    }

    // Block 172.16.x.x - 172.31.x.x
    const parts = hostname.split('.');
    if (parts.length === 4 && parts[0] === '172') {
      const secondOctet = parseInt(parts[1], 10);
      if (secondOctet >= 16 && secondOctet <= 31) {
        return false;
      }
    }

    // AWS / GCP Metadata endpoints
    if (hostname === '169.254.169.254' || hostname === 'metadata.google.internal') {
      return false;
    }

    return true;
  } catch (e) {
    return false;
  }
}

// @ts-nocheck
import { DOMParser } from "https://deno.land/x/deno_dom/deno-dom-wasm.ts";

export interface ParsedProduct {
  candidate_id?: string;
  nome: string | null;
  descricao: string | null;
  preco: number | null;
  moeda: string | null;
  nome_fornecedor: string | null;
  imagens: string[];
  origem_campos: Record<string, string>;
}

export function parseProductHtml(html: string, originalUrl: string): ParsedProduct {
  const doc = new DOMParser().parseFromString(html, "text/html");
  if (!doc) {
    throw new Error("Failed to parse HTML");
  }

  const result: ParsedProduct = {
    nome: null,
    descricao: null,
    preco: null,
    moeda: null,
    nome_fornecedor: null,
    imagens: [],
    origem_campos: {}
  };

  const getAbsoluteUrl = (relUrl: string) => {
    try {
      return new URL(relUrl, originalUrl).href;
    } catch {
      return relUrl;
    }
  };

  // 1. JSON-LD
  const jsonLdScripts = doc.querySelectorAll('script[type="application/ld+json"]');
  for (const script of jsonLdScripts) {
    try {
      const content = script.textContent;
      if (!content) continue;
      let data = JSON.parse(content);

      const processJsonLd = (obj: any) => {
        if (!obj) return;
        if (Array.isArray(obj)) {
          obj.forEach(processJsonLd);
          return;
        }
        if (obj['@graph'] && Array.isArray(obj['@graph'])) {
          obj['@graph'].forEach(processJsonLd);
          return;
        }

        if (obj['@type'] === 'Product') {
          if (!result.nome && obj.name) {
            result.nome = typeof obj.name === 'string' ? obj.name : obj.name[0];
            result.origem_campos['nome'] = 'json_ld';
          }
          if (!result.descricao && obj.description) {
            result.descricao = typeof obj.description === 'string' ? obj.description : obj.description[0];
            result.origem_campos['descricao'] = 'json_ld';
          }
          if (obj.image) {
            const imgs = Array.isArray(obj.image) ? obj.image : [obj.image];
            imgs.forEach((img: any) => {
              if (typeof img === 'string') {
                if (!result.imagens.includes(getAbsoluteUrl(img))) {
                  result.imagens.push(getAbsoluteUrl(img));
                }
              } else if (img && img.url) {
                if (!result.imagens.includes(getAbsoluteUrl(img.url))) {
                  result.imagens.push(getAbsoluteUrl(img.url));
                }
              }
            });
            if (result.imagens.length > 0 && !result.origem_campos['imagens']) {
              result.origem_campos['imagens'] = 'json_ld';
            }
          }

          if (obj.brand && obj.brand.name && !result.nome_fornecedor) {
            result.nome_fornecedor = typeof obj.brand.name === 'string' ? obj.brand.name : null;
            if (result.nome_fornecedor) result.origem_campos['nome_fornecedor'] = 'json_ld';
          }

          const offers = obj.offers;
          if (offers && !result.preco) {
            const offerList = Array.isArray(offers) ? offers : [offers];
            for (const offer of offerList) {
              const price = offer.price || offer.lowPrice;
              if (price !== undefined && price !== null) {
                const numPrice = parseFloat(String(price).replace(/[^0-9.]/g, ''));
                if (!isNaN(numPrice) && numPrice > 0) {
                  result.preco = numPrice;
                  result.moeda = offer.priceCurrency || 'BRL';
                  result.origem_campos['preco'] = 'json_ld';
                  result.origem_campos['moeda'] = 'json_ld';
                  break;
                }
              }
            }
          }
        }
      };

      processJsonLd(data);
    } catch (e) {
      // ignore JSON parse errors
    }
  }

  // 2. Open Graph
  if (!result.nome) {
    const ogTitle = doc.querySelector('meta[property="og:title"]');
    if (ogTitle) {
      result.nome = ogTitle.getAttribute('content');
      result.origem_campos['nome'] = 'open_graph';
    }
  }

  if (!result.descricao) {
    const ogDesc = doc.querySelector('meta[property="og:description"]');
    if (ogDesc) {
      result.descricao = ogDesc.getAttribute('content');
      result.origem_campos['descricao'] = 'open_graph';
    }
  }

  if (result.imagens.length === 0) {
    const ogImage = doc.querySelector('meta[property="og:image"]');
    if (ogImage && ogImage.getAttribute('content')) {
      result.imagens.push(getAbsoluteUrl(ogImage.getAttribute('content')!));
      result.origem_campos['imagens'] = 'open_graph';
    }
  }

  if (!result.preco) {
    const ogPrice = doc.querySelector('meta[property="product:price:amount"]');
    const ogCurrency = doc.querySelector('meta[property="product:price:currency"]');
    if (ogPrice && ogPrice.getAttribute('content')) {
      const p = parseFloat(ogPrice.getAttribute('content')!.replace(/[^0-9.]/g, ''));
      if (!isNaN(p) && p > 0) {
        result.preco = p;
        result.origem_campos['preco'] = 'open_graph';
        if (ogCurrency && ogCurrency.getAttribute('content')) {
          result.moeda = ogCurrency.getAttribute('content');
          result.origem_campos['moeda'] = 'open_graph';
        } else {
          result.moeda = 'BRL';
        }
      }
    }
  }

  // 3. Meta / Itemprop fallback
  if (!result.nome) {
    const metaTitle = doc.querySelector('title');
    if (metaTitle && metaTitle.textContent) {
      result.nome = metaTitle.textContent;
      result.origem_campos['nome'] = 'title';
    }
  }

  if (!result.descricao) {
    const metaDesc = doc.querySelector('meta[name="description"]');
    if (metaDesc) {
      result.descricao = metaDesc.getAttribute('content');
      result.origem_campos['descricao'] = 'meta';
    }
  }

  if (!result.nome_fornecedor) {
    const ogSiteName = doc.querySelector('meta[property="og:site_name"]');
    if (ogSiteName) {
      result.nome_fornecedor = ogSiteName.getAttribute('content');
      result.origem_campos['nome_fornecedor'] = 'open_graph';
    } else {
       try {
         result.nome_fornecedor = new URL(originalUrl).hostname.replace('www.', '');
         result.origem_campos['nome_fornecedor'] = 'url';
       } catch {}
    }
  }

  // Normalize and decode HTML entities
  const decodeHtmlEntities = (text: string) => {
    return text
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&amp;/g, '&')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'")
      .replace(/&#x27;/g, "'")
      .replace(/&nbsp;/g, ' ');
  };

  if (result.descricao) {
    let decoded = decodeHtmlEntities(result.descricao);
    // Strip HTML tags if any sneaked in
    result.descricao = decoded.replace(/<[^>]*>?/gm, ' ').replace(/\s+/g, ' ').trim();
  }
  if (result.nome) {
    let decoded = decodeHtmlEntities(result.nome);
    result.nome = decoded.replace(/<[^>]*>?/gm, ' ').replace(/\s+/g, ' ').trim();
  }

  return result;
}

export function parseProductsHtml(html: string, originalUrl: string): ParsedProduct[] {
  const doc = new DOMParser().parseFromString(html, "text/html");
  if (!doc) {
    throw new Error("Failed to parse HTML");
  }

  const candidates: ParsedProduct[] = [];
  const getAbsoluteUrl = (relUrl: string) => {
    try {
      return new URL(relUrl, originalUrl).href;
    } catch {
      return relUrl;
    }
  };

  const decodeHtmlEntities = (text: string) => {
    return text
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&amp;/g, '&')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'")
      .replace(/&#x27;/g, "'")
      .replace(/&nbsp;/g, ' ');
  };

  const normalizeText = (text: string | null) => {
    if (!text) return null;
    let decoded = decodeHtmlEntities(text);
    return decoded.replace(/<[^>]*>?/gm, ' ').replace(/\s+/g, ' ').trim() || null;
  };

  let candidateCount = 0;

  const addCandidate = (p: Partial<ParsedProduct>) => {
    if (candidates.length >= 100) return; // Limit to 100 candidates
    const nome = normalizeText(p.nome || null);
    if (!nome) return; // Name is required to be a valid candidate

    // Basic deduplication during parse
    const exists = candidates.find(c => c.nome === nome);
    if (exists) return;

    candidateCount++;
    candidates.push({
      candidate_id: `cand_${Date.now()}_${candidateCount}`,
      nome: nome,
      descricao: normalizeText(p.descricao || null),
      preco: p.preco || null,
      moeda: p.moeda || 'BRL',
      nome_fornecedor: p.nome_fornecedor || null,
      imagens: Array.isArray(p.imagens) ? p.imagens : [],
      origem_campos: p.origem_campos || {}
    });
  };

  // 1. Find ItemList or multiple Product objects in JSON-LD
  const jsonLdScripts = doc.querySelectorAll('script[type="application/ld+json"]');
  for (const script of jsonLdScripts) {
    try {
      const content = script.textContent;
      if (!content) continue;
      let data = JSON.parse(content);

      const processJsonLd = (obj: any) => {
        if (!obj) return;
        if (Array.isArray(obj)) {
          obj.forEach(processJsonLd);
          return;
        }
        if (obj['@graph'] && Array.isArray(obj['@graph'])) {
          obj['@graph'].forEach(processJsonLd);
          return;
        }

        if (obj['@type'] === 'ItemList' && Array.isArray(obj.itemListElement)) {
          obj.itemListElement.forEach((item: any) => {
            if (item.item && item.item['@type'] === 'Product') {
              processJsonLd(item.item);
            } else if (item.url) {
              // We might just have a list of URLs, but we need product details
              // We can't do much with just a URL without fetching it, which we don't do here.
            }
          });
          return;
        }

        if (obj['@type'] === 'Product') {
          const p: Partial<ParsedProduct> = { origem_campos: { 'nome': 'json_ld' } };
          p.nome = typeof obj.name === 'string' ? obj.name : (obj.name?.[0] || null);
          if (obj.description) {
            p.descricao = typeof obj.description === 'string' ? obj.description : (obj.description?.[0] || null);
            p.origem_campos!['descricao'] = 'json_ld';
          }
          p.imagens = [];
          if (obj.image) {
            const imgs = Array.isArray(obj.image) ? obj.image : [obj.image];
            imgs.forEach((img: any) => {
              if (typeof img === 'string') {
                p.imagens!.push(getAbsoluteUrl(img));
              } else if (img && img.url) {
                p.imagens!.push(getAbsoluteUrl(img.url));
              }
            });
            if (p.imagens.length > 0) p.origem_campos!['imagens'] = 'json_ld';
          }

          if (obj.brand && obj.brand.name) {
            p.nome_fornecedor = typeof obj.brand.name === 'string' ? obj.brand.name : null;
            if (p.nome_fornecedor) p.origem_campos!['nome_fornecedor'] = 'json_ld';
          }

          const offers = obj.offers;
          if (offers) {
            const offerList = Array.isArray(offers) ? offers : [offers];
            for (const offer of offerList) {
              const price = offer.price || offer.lowPrice;
              if (price !== undefined && price !== null) {
                const numPrice = parseFloat(String(price).replace(/[^0-9.]/g, ''));
                if (!isNaN(numPrice) && numPrice > 0) {
                  p.preco = numPrice;
                  p.moeda = offer.priceCurrency || 'BRL';
                  p.origem_campos!['preco'] = 'json_ld';
                  p.origem_campos!['moeda'] = 'json_ld';
                  break;
                }
              }
            }
          }
          addCandidate(p);
        }
      };
      processJsonLd(data);
    } catch (e) {
      // ignore
    }
  }

  // 2. Microdata fallback (very basic)
  if (candidates.length === 0) {
    const products = doc.querySelectorAll('[itemtype*="Product"]');
    products.forEach(prod => {
      const p: Partial<ParsedProduct> = { origem_campos: { 'nome': 'microdata' }, imagens: [] };
      const nameEl = prod.querySelector('[itemprop="name"]');
      if (nameEl) p.nome = nameEl.textContent;

      const descEl = prod.querySelector('[itemprop="description"]');
      if (descEl) p.descricao = descEl.textContent;

      const priceEl = prod.querySelector('[itemprop="price"]');
      if (priceEl) {
         let content = priceEl.getAttribute('content') || priceEl.textContent;
         if (content) {
             const num = parseFloat(content.replace(/[^0-9.]/g, ''));
             if (!isNaN(num) && num > 0) p.preco = num;
         }
      }
      const imgEl = prod.querySelector('img[itemprop="image"]');
      if (imgEl && imgEl.getAttribute('src')) {
         p.imagens!.push(getAbsoluteUrl(imgEl.getAttribute('src')!));
      }

      if (p.nome) addCandidate(p);
    });
  }

  // Set provider name if missing
  let defaultProvider = null;
  const ogSiteName = doc.querySelector('meta[property="og:site_name"]');
  if (ogSiteName) {
    defaultProvider = ogSiteName.getAttribute('content');
  } else {
    try {
      defaultProvider = new URL(originalUrl).hostname.replace('www.', '');
    } catch {}
  }

  candidates.forEach(c => {
    if (!c.nome_fornecedor) {
      c.nome_fornecedor = defaultProvider;
      c.origem_campos['nome_fornecedor'] = ogSiteName ? 'open_graph' : 'url';
    }
  });

  return candidates;
}
